namespace sv_e8a7166f888f402c8816e0b8a8e7ea07.Client.Models;

public sealed record Shipment(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

public sealed record StatusUpdate(
    DateTimeOffset Timestamp,
    string Description,
    string? Location);

using sv_e8a7166f888f402c8816e0b8a8e7ea07.Client.Models;

namespace sv_e8a7166f888f402c8816e0b8a8e7ea07.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_e8a7166f888f402c8816e0b8a8e7ea07.Client.Models;
using sv_e8a7166f888f402c8816e0b8a8e7ea07.Client.Services;

namespace sv_e8a7166f888f402c8816e0b8a8e7ea07.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment(
            TrackingNumber: "TRK-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 23, 9, 0, 0, TimeSpan.Zero), "Package picked up", "New York, NY"),
                new(new DateTimeOffset(2026, 5, 24, 14, 30, 0, TimeSpan.Zero), "Departed facility", "New York, NY"),
                new(new DateTimeOffset(2026, 5, 25, 8, 15, 0, TimeSpan.Zero), "Arrived at hub", "Chicago, IL"),
            }),

        ["TRK-002"] = new Shipment(
            TrackingNumber: "TRK-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 24, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 21, 10, 0, 0, TimeSpan.Zero), "Package picked up", "Seattle, WA"),
                new(new DateTimeOffset(2026, 5, 22, 6, 45, 0, TimeSpan.Zero), "In transit", "Portland, OR"),
                new(new DateTimeOffset(2026, 5, 23, 16, 0, 0, TimeSpan.Zero), "Out for delivery", "San Francisco, CA"),
                new(new DateTimeOffset(2026, 5, 23, 18, 22, 0, TimeSpan.Zero), "Delivered", "San Francisco, CA"),
            }),

        ["TRK-003"] = new Shipment(
            TrackingNumber: "TRK-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 30, 15, 0, 0, TimeSpan.Zero),
            StatusUpdates: new List<StatusUpdate>
            {
                new(new DateTimeOffset(2026, 5, 25, 11, 0, 0, TimeSpan.Zero), "Label created", "Dallas, TX"),
            }),
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_e8a7166f888f402c8816e0b8a8e7ea07.Client.Models
@using sv_e8a7166f888f402c8816e0b8a8e7ea07.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment <strong>@TrackingNumber</strong>…</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="Retry">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Status Updates</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.StatusUpdates)
            {
                <li>
                    <time datetime="@update.Timestamp.ToString("o")">@update.Timestamp.ToString("g")</time>
                    &mdash; @update.Description
                    @if (update.Location is not null)
                    {
                        <span class="update-location">(@update.Location)</span>
                    }
                </li>
            }
        </ul>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = default!;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override Task OnParametersSetAsync()
    {
        // Cancel any in-flight request when the tracking number changes
        CancelPending();
        return LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        _loading = true;
        _errorMessage = null;
        _shipment = null;

        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation away or disposal — do nothing
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading this shipment. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private Task Retry() => LoadShipmentAsync();

    private void CancelPending()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }

    public void Dispose()
    {
        CancelPending();
    }
}

